query:
SELECT 'AnaClara' as paciente, id, tipoUltrassom, JSON_KEYS(dados) as campos FROM ultrassons WHERE gestanteId = 330018 AND tipoUltrassom = 'ultrassom_seguimento' LIMIT 1
UNION ALL
SELECT 'Gisele' as paciente, id, tipoUltrassom, JSON_KEYS(dados) as campos FROM ultrassons WHERE gestanteId IN (SELECT id FROM gestantes WHERE LOWER(nome) LIKE '%gisele%batista%') AND tipoUltrassom = 'ultrassom_seguimento' LIMIT 1;

